try {
  const items = $input.all();

  /** @type {any[]} */
  const filtered = [];

  items.forEach((item, index) => {
    const row = item.json;
    const linkedinUrl    = (row.linkedin_url       || '').toString().trim();
    const enrichStatus   = (row.enrichment_status  || '').toString().trim();
    const firstName      = (row.first_name         || '').toString().trim();

    // Only process rows that:
    // 1. Have a LinkedIn URL
    // 2. Have NOT already been enriched
    // 3. Have NOT already been filled with a first_name
    if (linkedinUrl !== '' && enrichStatus === '' && firstName === '') {
      filtered.push({
        json: {
          ...row,
          row_number: index + 2,   // +2 accounts for the header row
          linkedin_url: linkedinUrl
        }
      });
    }
  });

  if (filtered.length === 0) {
    // Return a sentinel item so downstream nodes don't error on empty input
    return [{ json: { message: 'No unprocessed leads found.', total_leads: 0 } }];
  }

  return filtered;

} catch (e) {
  throw new Error('Filter Unprocessed Leads failed: ' + e.message);
}

