try {
  const allItems = $input.all();
  const results  = [];

  // Accepts standard LinkedIn /in/ profile URLs
  // Strips query strings and trailing slashes for cleanliness
  const linkedinRegex = /^https?:\/\/(www\.)?linkedin\.com\/in\/[a-zA-Z0-9._%-]+\/?(\?.*)?$/i;

  for (const item of allItems) {
    const data = item.json;
    const url  = (data.linkedin_url || '').toString().trim();
    const isValid = linkedinRegex.test(url);

    let cleanUrl = null;
    let username = null;

    if (isValid) {
      // Normalise: strip query params and trailing slash
      cleanUrl = url.split('?')[0].split('#')[0].replace(/\/$/, '');
      const match = cleanUrl.match(/linkedin\.com\/in\/([a-zA-Z0-9._%-]+)/i);
      username = match ? match[1] : null;
    }

    results.push({
      json: {
        ...data,
        linkedin_url:      cleanUrl || url,
        linkedin_username: username,
        url_valid:         isValid,
        validation_error:  isValid ? null : 'Invalid LinkedIn URL: ' + url
      }
    });
  }

  return results;

} catch (e) {
  return [{ json: { url_valid: false, validation_error: e.message } }];
}

